            let count = 0n;

            for (let d = 0; d <= upper_bound; d++) {

                const new_tight = tight && (d === upper_bound) ? 1 : 0;
                let new_last_val = last_val;
                let is_valid = true;

                // Check constraints if this digit d is part of the path sequence S
                const k_new = J_map[j]; 

